executePrompt:
async request => {
  return {
    hostAction: "playwright-send",
    editorSelector: '#m365-chat-editor-target-element[contenteditable="true"]',
    sendSelector: '#m365-chat-input-shared-container button.fai-SendButton:not([aria-label="Stop generating"])',
    responseSelector: '[id^="copilot-message-"][id$="-title"]',
    timeoutMs: 10000
  };
}

pollForResponse:
async state => {
  const stopVisible = Array.from(document.querySelectorAll('button[aria-label="Stop generating"]'))
    .some(element => element.getClientRects().length > 0);
  const responseCount = document.querySelectorAll('[id^="copilot-message-"][id$="-title"]').length;
  const previous = Number(state.ticket?.previousResponseCount ?? 0);
  const priorObserved = state.previousPoll?.generationObserved === true;
  const generationObserved = priorObserved || stopVisible;

  if (responseCount > previous && !stopVisible) {
    return {
      status: "complete",
      generationObserved,
      responseIndex: responseCount - 1,
      completedAt: Date.now()
    };
  }

  return { status: "pending", generationObserved };
}

getResult:
async state => {
  await new Promise(resolve => setTimeout(resolve, 300));
  const titles = document.querySelectorAll('[id^="copilot-message-"][id$="-title"]');
  const requestedIndex = Number(state.pollResult?.responseIndex);
  const index = Number.isInteger(requestedIndex) ? requestedIndex : titles.length - 1;
  if (index < 0 || index >= titles.length) throw new Error('The requested Copilot response was not found.');
  const titleElement = titles[index];
  let element = titleElement.parentElement;
  let responseContainer = null;
  for (let depth = 0; element && depth < 12; depth++) {
    const text = (element.innerText || '').trim();
    const withoutTitle = text.replace(/^Copilot said:\s*/i, '').trim();
    if ((withoutTitle && withoutTitle !== text) || (withoutTitle && !/^Copilot said:?$/i.test(withoutTitle))) {
      responseContainer = element;
      break;
    }
    element = element.parentElement;
  }
  if (!responseContainer) throw new Error('Could not locate the Copilot response container.');
  const clone = responseContainer.cloneNode(true);
  clone.querySelectorAll('button,script,style,[aria-hidden="true"]').forEach(node => node.remove());
  const copiedTitle = clone.querySelector(`[id="${CSS.escape(titleElement.id)}"]`);
  if (copiedTitle) copiedTitle.remove();
  return { text: (clone.innerText || clone.textContent || '').replace(/^Copilot said:\s*/i, '').trim() };
}
